  "function_code": "def calculate_average_effectiveness(feedback, treatment_name):
    """
    Calculate the average effectiveness of a specified treatment based on patient feedback.

    Parameters:
    - feedback (list of dict): List of patient feedback dictionaries.
        Each dict must have:
        - "name": str
        - "treatments": dict mapping treatment names (str) to ratings (int 1-10)
    - treatment_name (str): The name of the treatment to evaluate.

    Returns:
    - float: Average effectiveness rounded to 2 decimal places. Returns 0.0 if no ratings found.
    """
    total_rating = 0
    count = 0

    for patient in feedback:
        treatments = patient.get("treatments", {})
        if treatment_name in treatments:
            rating = treatments[treatment_name]
            total_rating += rating
            count += 1

    if count == 0:
        return 0.0

    average = total_rating / count
    return round(average, 2)

